import java.util.*;

public class Solution {

    public static int minCardsToAdd(List<Integer> cardTypes) {
        int maxVal = Collections.max(cardTypes);
        int minAdditions = Integer.MAX_VALUE;

        for (int k = 2; k <= maxVal; k++) {
            int totalAdd = 0;

            for (int x : cardTypes) {
                totalAdd += (k - x % k) % k;
            }

            minAdditions = Math.min(minAdditions, totalAdd);
        }

        return minAdditions;
    }

    public static void main(String[] args) {
        // Sample Input
        List<Integer> cardTypes = Arrays.asList(4, 7, 5, 11, 15);

        // Method Call
        int result = minCardsToAdd(cardTypes);

        // Output
        System.out.println("Minimum cards to add: " + result);
    }
}

